import{_ as h,o as _,c as d,a6 as u,gn as b,go as f,gp as k,gq as x,gr as K,es as P,gs as S,gt as C,gu as V,gv as v,gw as w,gh as A,gx as E,gy as p,gz as D,hs as i,gA as B,gB as N,gC as T,gD as I,gE as F,gF as o,gG as s,gH as g,gI as n,gJ as l,gK as $,gL as e,gM as y,gN as O,gO as j,gP as G,gQ as M,gR as Q,gS as R,gT as m,gU as H,gV as J,gW as L,gX as W,gY as X,gZ as q,ey as z,g_ as U,g$ as Y,h0 as Z,ht as pp,hu as sp,hv as rp,hw as tp,hx as ap,eu as ip,hy as op,hC as gp,hD as np,hE as lp,hF as ep,hG as mp,hH as cp,hI as hp,hK as _p,hL as r,hO as c,hP as t,hQ as dp}from"./chunks/framework.UYVGz2W_.js";const Cp=JSON.parse('{"title":"アセットのみの制作を作成","description":"","frontmatter":{},"headers":[],"relativePath":"ja/short-asset/index.md","filePath":"ja/short-asset/index.md"}'),up={name:"ja/short-asset/index.md"};function bp(fp,a,kp,xp,Kp,Pp){return _(),d("div",null,[...a[0]||(a[0]=[u('<h1 id="アセットのみの制作を作成" tabindex="-1">アセットのみの制作を作成 <a class="header-anchor" href="#アセットのみの制作を作成" aria-label="Permalink to “アセットのみの制作を作成”">​</a></h1><p>Kitsuでワークフローを設計し、より多くのユーザーを招待したので、今度は制作を作成します。</p><p><strong>新しい制作を作成</strong>ボタンをクリックします。</p><p><img src="'+b+'" alt="制作を作成"></p><p>制作物の名前を入力し、<strong>タイプ</strong>として<strong>アセットのみ</strong>を選択し、制作物のスタイル（2D、3D）を選択します。</p><p>次に、FPS数、アスペクト比、解像度などの技術情報を入力します。</p><p>これらのデータはすべて、Kitsuがアップロードされたビデオプレビューを再エンコードする際に使用されます。</p><p>次に、制作物の開始日と終了日を定義する必要があります。</p><p><img src="'+f+'" alt="プロダクションの追加"></p><p>プロダクションのワークフローは、次のパート3から6で定義できます。</p><p>アセットのタスクタイプ（3）、タスクのステータス（4）、アセットタイプ（5）を選択する必要があります。</p><p><img src="'+k+'" alt="Add a production Pipeline"></p><p>::: ヒント <strong>制作ワークフロー</strong>を作成するには、グローバルライブラリからタスクタイプを選択します。</p><p>タスクタイプをいくつか見落としていたことに気づいた場合は、後でそれらを作成することができます。</p><p><a href="./../configure-kitsu/#studio-workflow">スタジオワークフロー</a> のセクションを参照してください。 :::</p><p>次に、6はオプション部分です。アセットの入ったスプレッドシートがすでに用意されている場合。</p><p>詳細は<strong>インポートCSV</strong>のセクションを参照してください。</p><p>アセットのインポート</p><p>Import shot</p><p><img src="'+x+'" alt="All done"> ボタンですべてを検証します。</p><h2 id="kitsuグローバルページの紹介" tabindex="-1">Kitsuグローバルページの紹介 <a class="header-anchor" href="#kitsuグローバルページの紹介" aria-label="Permalink to “Kitsuグローバルページの紹介”">​</a></h2><p>Kitsuのグローバルアセットページへようこそ。</p><p>見てみましょう。</p><p><img src="'+K+'" alt="グローバルページの紹介"></p><p>上部 (1) には、<strong>グローバルナビゲーション</strong>があり、これはすべての制作ページで常に表示されます。</p><p><strong>左から右へ:</strong></p><h3 id="メインメニュー" tabindex="-1">メインメニュー <a class="header-anchor" href="#メインメニュー" aria-label="Permalink to “メインメニュー”">​</a></h3><p>左上のボタン、Kitsu<img src="'+P+'" alt="メインメニューボタン">（またはお客様のスタジオロゴ）をクリックすると、メインメニューが開きます。</p><p>メインメニューでは、割り当てられたタスク、制作物、グローバルおよびチームスケジュール、ワークフローのカスタマイズページ、およびKitsu設定に直接アクセスできます。</p><p>::: 詳細 メインメニューの詳細 <strong>ワークスペース</strong></p><ul><li>マイタスク：割り当てられたタスク</li><li>マイチェック：あなたの部署に応じて、ステータスが<strong>フィードバックリクエスト</strong>となっているすべてのタスク</li><li>マイプロダクション：プロダクションページの選択に戻ります。</li></ul><p><strong>スタジオ</strong></p><ul><li>プロダクション</li><li>担当者</li><li>タイムシート</li><li>メインスケジュール</li><li>チームスケジュール</li><li>すべてのタスク</li><li>ニュースフィード</li><li>エンティティ検索</li></ul><p><strong>ADMIN</strong></p><ul><li>部署</li><li>タスクの種類</li><li>アセットの種類</li><li>カスタムアクション</li><li>自動化</li><li>3D背景</li><li>ボット</li><li>設定</li><li>ログ</li></ul><p>::: 警告 権限の表示 ワークスペースセクションは、アーティストには表示されない「マイチェック」を除くすべての権限に対して有効になっています。</p><p>アーティスト（およびそれ以上）は、自身の<strong>タイムシート</strong>も表示でき、<strong>エンティティ検索</strong>にもアクセスできます :::</p><h3 id="ナビゲーション" tabindex="-1">ナビゲーション <a class="header-anchor" href="#ナビゲーション" aria-label="Permalink to “ナビゲーション”">​</a></h3><p>メインメニューアイコンの右側にナビゲーションのドロップダウンメニューが表示されます。</p><p><img src="'+S+'" alt="グローバルページの表示"></p><p>制作を選択できます。実際の制作名と実際のページ名が常に表示されます。</p><p>ドロップダウンメニューを使用して、制作から制作へと移動できます（複数の制作がある場合）。</p><p>制作を選択すると、次のドロップダウンメニューで、その制作の異なるページを移動することができます。</p><p>::: 詳細 ナビゲーションの詳細 最初のセクションは、タスクのトラッキングについてです</p><ul><li>アセット</li><li>編集（特定のタスクを作成した場合）</li></ul><p>2番目のセクションは、制作の側面についてです</p><ul><li>コンセプト</li><li>ブレークダウン</li><li>プレイリスト</li><li>ニュースフィード</li></ul><p>3番目のセクションは統計情報です。</p><ul><li>アセットタイプ統計</li></ul><p>4番目のセクションはチーム管理に関連しています。</p><ul><li>スケジュール</li><li>クォータ</li><li>チーム</li></ul><p>5番目のセクションは制作の設定です。</p><ul><li>設定</li></ul><p>::: ヒント アセットページから開始しますが、制作ホームページを他のエンティティに変更することができます（設定ページを参照）。 :::</p><p>::: 警告 エピソードなど、追加のナビゲーションレベルが必要だと気づいた場合は、制作タイプを<strong>テレビ番組</strong>に変更する必要があります。</p><p>逆に、ショットが必要だと気づいた場合は、制作タイプを<strong>アセットのみ</strong>から<strong>ショート</strong>に変更する必要もあります。 :::</p><h3 id="グローバル検索、ニュース、通知、およびドキュメント" tabindex="-1">グローバル検索、ニュース、通知、およびドキュメント <a class="header-anchor" href="#グローバル検索、ニュース、通知、およびドキュメント" aria-label="Permalink to “グローバル検索、ニュース、通知、およびドキュメント”">​</a></h3><p>グローバル検索はナビゲーションドロップダウンメニューの右側にあります。 4件の最初の検索結果を表示するクイックアクセス検索です。 さらに多くの結果やフィルタリングオプションが必要な場合は、<strong>エンティティ検索</strong>ページを参照してください。</p><p>次のアイコン <img src="'+C+'" alt="News"> は、ニュースとフィードバックページへの直接リンクです。</p><p>アニメーションGIFで新機能のすべてをご覧いただけます。また、Kitsuに追加してほしい次期機能に関するご意見もご投稿いただけます。</p><p>ベルのアイコンは、通知（割り当て、コメント、タグ）を表示します！<a href="../img/getting-started/notification_icon_on.png">通知</a>。未読の通知の数は、ベルのアイコンに表示されます。</p><p>アバターの直前のアイコンは、ドキュメントボタンです。 <img src="'+V+'" alt="ドキュメントボタン"> あなたが今読んでいるドキュメントです！</p><h3 id="個人設定" tabindex="-1">個人設定 <a class="header-anchor" href="#個人設定" aria-label="Permalink to “個人設定”">​</a></h3><p>アバターをクリックすると、メニュー（設定、ドキュメントなど）を開くことができます。</p><p><img src="'+v+'" alt="プロファイル拡大"></p><h2 id="タスクリスト" tabindex="-1">タスクリスト <a class="header-anchor" href="#タスクリスト" aria-label="Permalink to “タスクリスト”">​</a></h2><h3 id="エンティティスプレッドシート" tabindex="-1">エンティティスプレッドシート <a class="header-anchor" href="#エンティティスプレッドシート" aria-label="Permalink to “エンティティスプレッドシート”">​</a></h3><p>画面の2番目の部分は、すべてのエンティティ（アセット、ショット、シーケンス、編集）に共通です。これはグローバルなタスクリストです。</p><p>ここでは、各タスクのステータス、割り当て、優先度などを確認できます。</p><p>::: ヒント スプレッドシートの最初の行と列のヘッダーは、ページを下にスクロールしても常にページの先頭に表示されます。</p><p>また、他の列を常に表示しておくために「固定」することもできます。 :::</p><h3 id="フィルター" tabindex="-1">フィルター <a class="header-anchor" href="#フィルター" aria-label="Permalink to “フィルター”">​</a></h3><p>左側の最初の要素はフィルターボックスです。単純なフィルタリング、順序、アセットタイプなど、任意の文字列を入力することができます。</p><p>より高度なフィルタリングが必要な場合は、フィルタービルダーボタンを使用してください。</p><p><img src="'+w+'" alt="フィルタービルダー"></p><p>すべてのフィルターを保存し、ページとして使用することができます。</p><h3 id="表示の簡素化" tabindex="-1">表示の簡素化 <a class="header-anchor" href="#表示の簡素化" aria-label="Permalink to “表示の簡素化”">​</a></h3><p>画面の右側には、左から右に、アサインメントの表示/非表示、追加カラムの表示/非表示、サムネイルの拡大/縮小を行うためのボタンがあります。 <img src="'+A+'" alt="表示と非表示オプション"></p><h3 id="インポート-エクスポート" tabindex="-1">インポート / エクスポート <a class="header-anchor" href="#インポート-エクスポート" aria-label="Permalink to “インポート / エクスポート”">​</a></h3><p>バッチインポートサムネイル <img src="'+E+'" alt="バッチインポートサムネイル">、最後にインポート <img src="'+p+'" alt="インポートボタン"> またはエクスポート <img src="'+D+'" alt="エクスポートボタン"> データの</p><h3 id="メタデータカラム" tabindex="-1">メタデータカラム <a class="header-anchor" href="#メタデータカラム" aria-label="Permalink to “メタデータカラム”">​</a></h3><p>以下に、カラムの名前があります。<strong>名前</strong>の隣にある(+)をクリックすると、<img src="'+i+'" alt="Add metadata column"> が表示され、新しいメタデータカラムを作成できます。次に、タスクタイプのカラムの名前があります。</p><h3 id="ビューのカスタマイズ" tabindex="-1">ビューのカスタマイズ <a class="header-anchor" href="#ビューのカスタマイズ" aria-label="Permalink to “ビューのカスタマイズ”">​</a></h3><p>画面の一番右側、スクロールバーの隣に、テキストカラムの表示/非表示を切り替えるオプションがあります</p><p><img src="'+B+'" alt="テキストカラムの表示/非表示">。</p><h3 id="ビューのまとめ" tabindex="-1">ビューのまとめ <a class="header-anchor" href="#ビューのまとめ" aria-label="Permalink to “ビューのまとめ”">​</a></h3><p>最後の部分（4）は、画面の下部にある、表示されたページのまとめです。つまり、ページをフィルタリングすると、まとめも更新されます。</p><p>表示されているページのサマリーが表示されます。 要素（アセットまたはショット）の数、見積もり日数、およびすでに費やした日数の合計を確認できます。</p><h2 id="アセットの作成" tabindex="-1">アセットの作成 <a class="header-anchor" href="#アセットの作成" aria-label="Permalink to “アセットの作成”">​</a></h2><h3 id="最初のアセットの作成" tabindex="-1">最初のアセットの作成 <a class="header-anchor" href="#最初のアセットの作成" aria-label="Permalink to “最初のアセットの作成”">​</a></h3><p>制作物を制作し、Kitsuインターフェースの概要を理解したので、最初のアセットを作成してみましょう。</p><p>アセットページで、<strong>[アセットを追加]</strong>をクリックします。</p><p><img src="'+N+'" alt="Asset page first time"></p><p>::: 警告 アセットを作成すると、タスクワークフローが適用され、<strong>すべてのタスクがアセットと同時に作成されます</strong>。 :::</p><p>ポップアップウィンドウが開きます。</p><p><strong>アセットタイプ</strong>を選択するよう求められます（1）。 新しいアセットタイプを追加していない場合、Kitsuは「キャラクター」、「環境」、「エフェクト」、「小道具」などの例を提供します。 まずはキャラクターから始めましょう。</p><p><strong>名前</strong> (2) を付け、アーティストが何をすべきか、またアセットを素早く識別できるようにするための説明を入力します。</p><p>複数のアセットを作成する場合は、<strong>「確認して戻る」</strong>をクリックします。</p><p><img src="'+T+'" alt="アセットの作成"></p><p>アセットの種類を変更して、アセットを追加し続けることができます。</p><p>::: ヒント 「確認して戻る」をクリックするたびに、新しく作成したアセットが背景に表示されます。 :::</p><p>最後のアセットを追加したら、 「確認」をクリックします。アセットが作成され、ウィンドウが閉じます。</p><p>::: ヒント 「確認して戻る」をクリックしたものの、追加するアセットがもうないことに気づいた場合は、「閉じる」をクリックすると、ウィンドウがキャンセルされます。 :::</p><p><img src="'+I+'" alt="グローバルアセットページ"></p><p>また、アセットワークフローで選択されたタスクも同時に作成されます。</p><p>さらに<strong>アセット</strong>を追加する必要がある場合は、<strong>+ アセットの作成</strong>ボタンをクリックします。</p><p>::: 詳細 CSVスプレッドシートファイルからのアセットの作成 アセットのリストがすでにスプレッドシートファイルに用意されているかもしれません。 Kitsuでは、それらをインポートする方法が2つあります。1つ目は、<code>.csv</code>ファイルをインポートし、データを直接Kitsuにコピー＆ペーストする方法です。</p><p>まず、スプレッドシートを<code>.csv</code>ファイルとして保存します。</p><p>次に、Kitsuのアセットページに戻り、<strong>インポート</strong>アイコンをクリックします。 <img src="'+p+'" alt="インポートアイコン"></p><p>ポップアップウィンドウの<strong>「CSVからデータをインポート」</strong>が開きます。<strong>「参照」</strong>をクリックして、<code>.csv</code>ファイルを選択します。</p><p><img src="'+F+'" alt="CSVファイルのインポート"></p><p>結果を確認するには、<strong>「プレビュー」</strong>ボタンをクリックします。</p><p>データのプレビューで列の名前を確認し、調整することができます。</p><p>注：<strong>「エピソード」</strong>列は、<strong>「テレビ番組」</strong>制作の場合のみ必須です。</p><p><img src="'+o+'" alt="インポートデータ コピー＆ペーストデータ"></p><p>すべてが適切であることを確認したら、<strong>「確認」</strong>ボタンをクリックしてデータをKitsuにインポートします。</p><p>これで、すべての資産がKitsuにインポートされ、設定に従ってタスクが作成されました。</p><p><img src="'+s+'" alt="インポートデータコピーペーストデータ"> ::::</p><p>:::: 詳細 スプレッドシートファイルのコピー/ペーストによる資産の作成</p><p>スプレッドシートを開き、データを選択してコピーします。</p><p><img src="'+g+'" alt="コピーデータのインポート"></p><p>次に、Kitsuのアセットページに戻り、<strong>インポート</strong>アイコンをクリックします <img src="'+p+'" alt="インポートアイコン">。</p><p>ポップアップウィンドウ<strong>CSVからのインポート</strong>が開きますので、<strong>CSVデータの貼り付け</strong>タブをクリックします。</p><p><img src="'+n+'" alt="インポートデータのコピー＆ペーストタブ"></p><p>以前に選択したデータを貼り付け、<strong>[プレビュー]</strong>ボタンで結果を確認できます。</p><p><img src="'+l+'" alt="インポートデータのコピー＆ペーストデータ"></p><p>データのプレビューで列の名前を確認し、調整することができます。</p><p>注意：<strong>エピソード</strong>の列は、<strong>テレビ番組</strong>の制作の場合のみ必須です。</p><p><img src="'+o+'" alt="インポートデータ コピーペーストデータ"></p><p>すべて問題なければ、<strong>確認</strong>ボタンをクリックしてデータをKitsuにインポートします。</p><p>これで、すべてのアセットがKitsuにインポートされ、設定に従ってタスクが作成されました。</p><p><img src="'+s+'" alt="インポートデータ コピーペーストデータ"> :::</p><h3 id="アセットの詳細を確認する" tabindex="-1">アセットの詳細を確認する <a class="header-anchor" href="#アセットの詳細を確認する" aria-label="Permalink to “アセットの詳細を確認する”">​</a></h3><p>アセットの詳細を確認するには、その名前をクリックします。</p><p><img src="'+$+'" alt="アセットの詳細"></p><p>新しいページが開き、右側にタスク、アサイン、ステータスニュースフィードの一覧が表示されます。</p><p><img src="'+e+'" alt="アセット詳細ページ"></p><p>各タスクのステータスをクリックすると、コメントパネルが開き、コメントの履歴や異なるバージョンを確認できます。</p><p><img src="'+y+'" alt="アセット詳細ページ"></p><p>また、<strong>キャスティング</strong>にもアクセスできます。</p><p><img src="'+O+'" alt="アセット詳細キャスティング"></p><p>このアセットに関連付けられた<strong>コンセプト</strong>にもアクセスできます。</p><p><img src="'+j+'" alt="アセット詳細キャスティング"></p><p><strong>スケジュール</strong>は、タスクタイプのページのデータを事前に記入している場合に表示されます。データがすでに記入されている場合は、ここで直接修正することができます。</p><p><img src="'+G+'" alt="アセット詳細キャスティング"></p><p>さまざまなタスクタイプでアップロードされた<strong>プレビューファイル</strong>、</p><p><img src="'+M+'" alt="アセット詳細のキャスティング"></p><p>そして、このアセットのタスクでタイムシートが記入された場合の<strong>タイムログ</strong>。</p><p><img src="'+Q+'" alt="アセット詳細のキャスティング"></p><h2 id="アセットを作成した後にタスクを追加する" tabindex="-1">アセットを作成した後にタスクを追加する <a class="header-anchor" href="#アセットを作成した後にタスクを追加する" aria-label="Permalink to “アセットを作成した後にタスクを追加する”">​</a></h2><p>アセットを作成した後に、タスクが欠けていることに気づいた場合でも、追加することができます。</p><p>まず、欠けているタスクタイプが、タスクタイプタブの設定ページに追加されていることを確認してください。</p><p>次に、アセットページに戻り、<strong>+ タスクを追加</strong>をクリックします</p><h3 id="アセットを更新する" tabindex="-1">アセットを更新する <a class="header-anchor" href="#アセットを更新する" aria-label="Permalink to “アセットを更新する”">​</a></h3><p>いつでもアセットを更新し、名前やアセットタイプを変更したり、説明文やグローバルページに追加したカスタム情報を修正することができます。</p><p>アセットを編集するには、アセットページに移動し、編集したいアセットの上にカーソルを合わせて、<strong>[編集]</strong>ボタンをクリックします ！<a href="../img/getting-started/edit_button.png">編集ボタン</a> (1) 行の右側にある</p><p><img src="'+R+'" alt="アセットの編集"></p><p>アセットのメインページの説明を拡張するには、最初の語句 (2) をクリックすると、説明の全文を含むポップアップが開きます。</p><p>アセットを削除するには、FAQ : アセットの削除方法を参照してください。</p><p>::: 詳細 CSV インポートによるアセットの更新 CSV インポートを使用すると、データを素早く更新することができます。</p><p>アセットの<strong>タイプ</strong>、<strong>アサインメント</strong>、タスクの<strong>ステータス</strong>を更新したり、<strong>コメント</strong>を追加したりすることができます。</p><p><strong>既存のデータを更新する</strong>オプションをオンにする必要があります。すると、更新される行が 青くハイライトされます。</p><p><img src="'+m+'" alt="インポートデータ コピー＆ペーストデータ"></p><p>::::</p><p>:::: 詳細 スプレッドシートファイルのコピー＆ペーストによるアセットの更新</p><p>スプレッドシートを開き、データを選択してコピーします。</p><p><img src="'+g+'" alt="コピーデータのインポート"></p><p>次に、Kitsuのアセットページに戻り、<strong>インポート</strong>アイコンをクリックします <img src="'+p+'" alt="インポートアイコン">。</p><p>ポップアップウィンドウ<strong>CSVからのインポート</strong>が開きますので、<strong>CSVデータの貼り付け</strong>タブをクリックします。</p><p><img src="'+n+'" alt="インポートデータのコピー＆ペーストタブ"></p><p>以前に選択したデータを貼り付け、<strong>[プレビュー]</strong>ボタンで結果を確認できます。</p><p><img src="'+l+'" alt="インポートデータのコピー＆ペーストデータ"></p><p>データをプレビューして、列の名前を確認し、調整することができます。</p><p>注意：<strong>エピソード</strong>の列は、<strong>テレビ番組</strong>制作の場合のみ必須です。</p><p>既存のデータを更新**オプションをオンにする必要があります。すると、更新される行が 青くハイライトされます。</p><p><img src="'+m+'" alt="データのインポート コピー＆ペースト"></p><p>これで、すべてのアセットがKitsuにインポートされ、設定に従ってタスクが作成されました。</p><p><img src="'+s+'" alt="インポートデータコピーペーストデータ"> :::</p><h2 id="コンセプトの作成" tabindex="-1">コンセプトの作成 <a class="header-anchor" href="#コンセプトの作成" aria-label="Permalink to “コンセプトの作成”">​</a></h2><h3 id="コンセプトのアップロード" tabindex="-1">コンセプトのアップロード <a class="header-anchor" href="#コンセプトのアップロード" aria-label="Permalink to “コンセプトのアップロード”">​</a></h3><p><strong>コンセプト</strong>を作成するには、ナビゲーションメニューから<strong>コンセプト</strong>ページに移動します。</p><p><img src="'+H+'" alt="コンセプトメニュー"></p><p>コンセプトをアップロードするには、「<strong>コンセプトへの新しい参照を追加</strong>」ボタンをクリックします。</p><p>一度に1つまたは複数のコンセプトをアップロードできます。</p><p><img src="'+J+'" alt="コンセプトの空ページ"></p><p>プレビューをアップロードすると、コンセプトページは次のようになります。</p><p><img src="'+L+'" alt="コンセプトの入力ページ"></p><p>コンセプトとやりとりするには2つの方法があります。画像をクリックすると拡大表示されます。 もう1つは、ステータス部分をクリックして右側の<strong>コメントパネル</strong>を開く方法です。</p><p>コメントパネルでは、2つのオプションがあります。コンセプトを既存のアセットにリンクするか、削除するかです。 また、アセットにコメントを追加したり、ステータスを変更することもできます。</p><p><strong>コンセプト</strong>ごとに1つのバージョンを持つことが基本です。承認されていない場合は、同じコンセプトの複数のバージョンを作成しないよう、新しいコンセプトをアップロードする必要があります。</p><p>1つのコンセプトは1つのタスクです。</p><p><img src="'+W+'" alt="コンセプトオプション"></p><h3 id="コンセプトとアセットのリンク" tabindex="-1">コンセプトとアセットのリンク <a class="header-anchor" href="#コンセプトとアセットのリンク" aria-label="Permalink to “コンセプトとアセットのリンク”">​</a></h3><p>コンセプトをアップロードすると、アセットにリンクすることができます。</p><p>アセットのステータス部分にリンクが表示されます。</p><p>コンセプトのステータス部分をクリックすると、右側にコメントパネルが開きます。</p><p><img src="'+X+'" alt="コンセプトコメントパネル"></p><p>コメントパネルの上部には、コンセプトをアセットにリンクするオプションと、コンセプトを削除するオプションがあります。</p><p>アセットをリンクするには、[リンク] ボタン <img src="'+q+'" alt="リンクボタン"> をクリックします。</p><p>Kitsu は、アップロードしたコンセプトにリンク可能なすべての <strong>アセット</strong> を表示します。</p><p>Kitsu は、コメントパネルの上部にリンクされたアセットをリスト表示します。現時点では、リンクはありません。</p><p><img src="'+z+'" alt="コンセプトのリンク"></p><p>アセットをリンクするには、それをクリックする必要があります。リンクされたアセットの名前は、画面の上部およびコンセプトのプレビューの下部に表示されます。</p><p><img src="'+U+'" alt="コンセプトのアセットがリンクされた状態"></p><p>コンセプトがアセットにリンクされると、アセットの詳細ページで確認できます。</p><p>アセットページに戻り、コンセプトを確認したいアセット名をクリックします。</p><p><img src="'+e+'" alt="アセット詳細ページ"></p><p>デフォルトでは、キャスティングの詳細が画面の2番目の部分に表示されます。 ドロップダウンメニューを使用してコンセプトを選択します。</p><p><img src="'+Y+'" alt="アセット詳細コンセプト"></p><p>コンセプトセクションに入ると、このアセット用に作成されたすべてのコンセプトが表示されます。ステータスごとにフィルタリングすることができます。</p><p><img src="'+Z+'" alt="アセット詳細コンセプトリスト"></p><h2 id="カスタムメタデータカラムの作成" tabindex="-1">カスタムメタデータカラムの作成 <a class="header-anchor" href="#カスタムメタデータカラムの作成" aria-label="Permalink to “カスタムメタデータカラムの作成”">​</a></h2><p>一般的なスプレッドシートページにさらに情報を追加するには、カスタムの<strong>メタデータカラム</strong>を作成する必要があります。</p><p>難易度レベル、天候、タグなど、ページに追加する追加情報があるかもしれません。テキスト（または数値）情報をすべてカスタムメタデータ列に保存できます。</p><p>名前列の近くにある<strong>+</strong>をクリックします。</p><p><img src="'+i+'" alt="メタデータ列"></p><p>タイプ**オプションでは、情報をどのように保存するかを選択できます。</p><ul><li>自由入力の<strong>テキスト</strong>、</li><li><strong>数値</strong>、</li><li><strong>チェックボックス</strong>、</li><li><strong>値のリスト</strong>、</li><li><strong>タグのリスト</strong>、</li><li><strong>チェックリスト</strong>。</li></ul><p><img src="'+pp+'" alt="メタデータカラムの詳細"></p><p>::: 警告 テキスト、数値、およびチェックボックスでは、各エンティティに異なる情報を追加できます。最初に計画する必要はありません。</p><p>リスト値、タグリスト、およびチェックリストでは、各エンティティに同じ選択肢が与えられます。さらに、これは現在入力する必要があります。</p><p><img src="'+sp+'" alt="メタデータカラムリスト"></p><p><strong>利用可能な値</strong>の下にリスト要素を入力し、<strong>値を追加</strong>をクリックして確認します。 :::</p><p>メタデータカラムを1つまたは複数の<strong>部署</strong>にリンクすることもできます。</p><p>::: ヒント メタデータカラムを部署にリンクします。アーティスト/スーパーバイザーは、自分のToDoページおよび部門フィルタリングビューでこれを見ることができます。</p><p>メタデータ列を1つまたは複数の部門にリンクすることができます。リストから部門をクリックし、<strong>追加</strong>をクリックして有効にします。</p><p>ここでは、VFX列が2つの部門にリンクされています。</p><p><img src="'+rp+'" alt="部門メタデータ列フィルタリングビュー"></p><p>:::</p><p>::: 詳細 メタカラムの編集 アセットまたはショットのグローバルページで、メタカラムの右側にある矢印をクリックし、<strong>[編集]</strong>をクリックします。</p><p><img src="'+tp+'" alt="メタカラムの編集"> :::</p><p>この情報は、グローバルスプレッドシートページで直接入力できます。 ケースは編集可能です。</p><p><img src="'+ap+'" alt="メタデータ列の詳細"></p><p>::: ヒント 左側の複数のエンティティを選択し、メタデータ列を一括で変更することができます。 :::</p><p>::: 詳細 手動で編集 編集ボタン <img src="'+ip+'" alt="編集ボタン"> を使用して情報を変更することもできます。</p><p>編集ポップアップに新しい行が表示されます。リストから情報を選択することもできますが、 代わりに、テキストや数値を直接入力したり、チェックボックスにチェックを入れたり、チェックリストを使用したりすることもできます。</p><p>編集が完了したら、必ず「確認」ボタンをクリックしてください。</p><p><img src="'+op+'" alt="メタデータカラムの詳細"> :::</p><p>メタデータ列を編集または削除する場合は、スプレッドシートの一般ページに移動します。 メタデータ列の名前の近くにある矢印をクリックします！<a href="../img/getting-started/arrow.png">メタデータ列の詳細</a>。</p><p>::: ヒント この新しい列を使用して、グローバルページを<strong>ソート</strong>することができます。列名の右にある矢印をクリックして、このメニューを開きます。次に、<strong>ソート</strong>をクリックします。</p><p>メタデータ列を左側に<strong>固定</strong>することもできます。 :::</p><h2 id="編集の作成" tabindex="-1">編集の作成 <a class="header-anchor" href="#編集の作成" aria-label="Permalink to “編集の作成”">​</a></h2><p>Kitsuでは、<strong>編集</strong>レベルでタスクを追跡することができます。</p><p>特に、 複数の検証ステップで複数の編集を追跡する必要がある場合に便利です。例えば、映画全体、複数の予告編、ファースト・エディット、ファイン・エディット、ミックスなどを追跡することができます。</p><p>::: 警告 デフォルトでは、<strong>Edit</strong> ページは、<strong>制作ライブラリ</strong>（設定ページ）にそれ用のタスクタイプが作成されるまで表示されません :::</p><p>このページを使用するには、まず <strong>グローバルライブラリ</strong>に <strong>Edit</strong> 属性を持つ専用のタスクタイプを作成する必要があります。</p><p>新しい <strong>タスクタイプ</strong> を作成するには、<strong>新しいタスクタイプの作成</strong> セクションを参照してください。</p><p><a href="./../configure-kitsu/#タスクの種類">新しいタスクタイプの作成</a></p><p>グローバルライブラリで<strong>タスクタイプ</strong>を作成したら、<strong>プロダクションライブラリ</strong>に追加します。 すると、ナビゲーションのドロップダウンメニューに<strong>Edit</strong>が表示されます。</p><p><img src="'+gp+'" alt="Navigation Edit"></p><p>この新しいページは、アセットおよびショットのグローバルページと同様に動作します。<strong>+ 新規編集</strong> ボタンで編集を追加できます。</p><p>タスクの割り当て、レビュー、ステータスの変更などを行うことができます。</p><p>メタデータ列を追加したり、説明を記入したりすることができます。</p><p>::: ヒント 配信内容によっては、<strong>編集</strong> ごとに解像度を変更することもできます。 :::</p><p>::: 警告 詳細ページは他のエンティティとは異なります。</p><p><strong>Edit</strong> が特定のロングビデオに焦点を当てているため、詳細ページはコメントの詳細ページにより似たものとなっています。 :::</p><p>このページでは、アセットやショットのエンティティと同様に、Editエンティティの<strong>名前の変更</strong>や<strong>削除</strong>が可能です。</p><h2 id="ブレークダウンリストの作成" tabindex="-1">ブレークダウンリストの作成 <a class="header-anchor" href="#ブレークダウンリストの作成" aria-label="Permalink to “ブレークダウンリストの作成”">​</a></h2><p>ブレークダウンを記入すると、アセットの組み立てに役立ちます。 ブレークダウンには、メインのアセットを作成するために追加する必要のあるアセットの詳細がすべて記載されています。</p><p>ドロップダウンメニューで <strong>BREAKDOWN</strong> を選択します。</p><p><img src="'+np+'" alt="drop down Menu breakdown"></p><p>ブレークダウンページの左側にはアセットメニュー（1）があります。作成したものの中から選択できます。これらは画面の右側部分で、 作成したすべてのアセットがこの制作で利用可能です（3）。さらに、 中央セクションでは、アセットの選択（2）を行います。</p><p><img src="'+lp+'" alt="ブレークダウンページ"></p><p>したがって、キャストしたいアセットを選択する必要があります。</p><p>サムネイルがまだない場合はアセットをテキストで表示したり、 サムネイルのサイズを拡大することもできます。</p><p><img src="'+ep+'" alt="Breakdown page text display"></p><p>また、ブレイクダウン中にアセットをリストに追加する必要があることに気づくかもしれません。</p><p>ブレークダウンページから直接新しいアセットを作成することができます。「利用可能なすべてのアセット」の右にある「+」をクリックします。</p><p><img src="'+mp+'" alt="ブレークダウンページのアセット作成"></p><p>また、複数のアセットを一度に選択することもできます。最初の「アセット」をクリックし、「シフト」キーを押したまま、選択する最後の「アセット」をクリックします。</p><p><img src="'+cp+'" alt="Breakdown page global bulk select"></p><p>次に、割り当てたいアセットをクリックします。 キャラクター、背景、... 右側部分 (3) から。 複数のアセットを選択した場合、選択したアセットが多数のアセットに適用されます。</p><p>アセットで満たされたアセットをコピーし、このアセット選択を別のアセットに貼り付けます。</p><p>アセットの上にカーソルを移動させると、<strong>+1</strong> または <strong>+10</strong> と表示されます。これは このアセットを追加した回数であり、必要なだけクリックできます。</p><p><img src="'+hp+'" alt="Breakdown add asset"></p><p>画面中央（2）にアセットが表示されているのが確認できます。 アセット名の隣には、追加された回数が表示されています。この 例では、キャラクターアセット「ラマ」を2回追加しています。</p><p>誤ってアセットを2回追加してしまった場合は、画面中央部分に戻って、このショットのアセットを選択する必要があります（2）。そこから、<strong>-1</strong>をクリックします。 このショットの作業が完了したら、他のショットの作業に進みます。 選択した内容は自動的に保存されます。</p><p><img src="'+_p+'" alt="Breakdown remove asset"></p><p>作業中に新しいアセットが作成された場合は、アセットページに戻り ページ（ドロップダウンメニューを使用）に戻り、必要なアセットを作成します。 以前に作成されたタスクは、これらの新しいアセットに即座に適用されます。 ただし、割り当てを実行する必要があります。その後、 ブレークダウンを続行できます。</p><p>これで、<strong>ブレークダウン</strong>ページは次のようになります。</p><p><img src="'+r+'" alt="ブレークダウンにアセットを一括追加"></p><p>::: 詳細 CSVファイルから内訳リストを作成する</p><p>すでにスプレッドシートファイルで内訳リストが準備できているかもしれません。 Kitsuでは、それをインポートする方法が2つあります。1つ目は、.csvファイルを直接インポートする方法、2つ目は、データを直接Kitsuにコピー＆ペーストする方法です。</p><p>まず、Kitsuの推奨に従って、スプレッドシートを <code>.csv</code> ファイルとして保存します。</p><p>インポート] ボタンをクリックしてください！[インポート] ボタン (../img/getting-started/import.png)</p><p>ポップアップウィンドウ [CSV からのインポート] が開きます。 [参照] をクリックして <code>.csv</code> ファイルを選択してください。</p><p><img src="'+c+'" alt="CSV ファイルのインポートの分割"></p><p>結果を確認するには、[プレビュー] ボタンをクリックしてください。</p><p>データのプレビューで列名を確認し、必要に応じて調整します。</p><p>注：<strong>[エピソード]</strong>列は、<strong>[テレビ番組]</strong>制作の場合のみ必須です。</p><p><img src="'+t+'" alt="ブレークダウンインポートプレビュー"></p><p>すべてが適切であることを確認したら、<strong>[確認]</strong>ボタンをクリックしてデータをKitsuにインポートします。</p><p>これで、ブレークダウンがKitsuにインポートされました。</p><p><img src="'+r+'" alt="ブレークダウンインポートプレビュー"> :::</p><p>::: 詳細 スプレッドシートファイルをコピー/ペーストしてブレークダウンリストを作成</p><p>スプレッドシートを開き、データを選択してコピーします。</p><p><img src="'+dp+'" alt="インポートコピーデータ"></p><p>次に、Kitsuのブレークダウンページに戻り、<strong>インポート</strong>アイコンをクリックします <img src="'+p+'" alt="インポートアイコン">。</p><p>ポップアップウィンドウ「<strong>CSVからデータをインポート</strong>」が開きますので、「<strong>CSVデータを貼り付け</strong>」タブをクリックします。</p><p><img src="'+c+'" alt="インポートデータコピーペーストタブ"></p><p>以前に選択したデータを貼り付け、<strong>[プレビュー]</strong> ボタンで結果を確認できます。</p><p><img src="'+t+'" alt="データのコピー＆ペースト"></p><p>データのプレビューで列の名前を確認し、調整できます。</p><p>注：<strong>[エピソード]</strong> 列は、<strong>[テレビ番組]</strong> 制作の場合のみ必須です。</p><p><img src="'+t+'" alt="インポートデータのコピー＆ペースト"></p><p>すべてが正しく入力されたら、<strong>Confirm</strong>ボタンをクリックしてデータをKitsuにインポートします。</p><p>これで、すべてのアセットがKitsuにインポートされました。</p><p><img src="'+r+'" alt="インポートデータのコピー＆ペースト"> :::</p>',308)])])}const Vp=h(up,[["render",bp]]);export{Cp as __pageData,Vp as default};
